import{_ as t,o as a,c as o,a5 as l}from"./chunks/framework.B5tqjWbr.js";const h=JSON.parse('{"title":"教程 0007：Boost 故障锁存与复位状态机","description":"","frontmatter":{"title":"教程 0007：Boost 故障锁存与复位状态机","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0007-boost-fault-state-machine.html","status":"learning","visibility":"public","summary":"Imported from 0007-boost-fault-state-machine.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0007-boost-fault-state-machine.md","filePath":"content/power/lessons/0007-boost-fault-state-machine.md","lastUpdated":null}'),p={name:"content/power/lessons/0007-boost-fault-state-machine.md"};function i(s,e,r,c,n,d){return a(),o("div",null,[...e[0]||(e[0]=[l(`<h1 id="教程-0007-boost-故障锁存与复位状态机" tabindex="-1">教程 0007：Boost 故障锁存与复位状态机 <a class="header-anchor" href="#教程-0007-boost-故障锁存与复位状态机" aria-label="Permalink to &quot;教程 0007：Boost 故障锁存与复位状态机&quot;">​</a></h1><p>中文主讲。一个概念：为什么故障采样消失后，UPS 软件仍然不能立刻重新打开 PWM。</p><pre><code>目录
</code></pre><ul><li><p>它是什么</p></li><li><p>为什么 UPS 需要它</p></li><li><p>物理直觉</p></li><li><p>数学形式</p></li><li><p>一个仿真任务与仿真观察</p></li><li><p>固件落地</p></li><li><p>常见误解</p></li><li><p>验收标准、复盘问题、导师问题</p></li></ul><p>**保密边界：**本节只使用教学参数和教学脚本，不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>故障锁存（fault latch）是指：一旦检测到严重故障，软件把故障码保存下来，关闭功率输出，并且不因为下一次采样恢复正常就自动清除。</p><p>状态机（state machine）是把软件运行过程分成有限状态的工程写法。本节只看三个状态：</p><p>RUN -&gt; FAULT_LATCHED -&gt; RESET_WAIT -&gt; RUN</p><p>本节继续使用 脉宽调制（pulse-width modulation / PWM） 使能作为输出是否允许工作的标志。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）既要保持供电，也要防止危险输出。严重故障不能只按瞬时采样判断，因为短暂过压可能已经说明硬件、负载或控制环路出现风险。</p><ul><li><p>故障可能只持续几个控制周期，但仍需要记录和处理。</p></li><li><p>如果采样刚恢复就自动打开 PWM，可能造成反复启停。</p></li><li><p>复位通常要等待母线、电感电流、温度或驱动状态回到安全区。</p></li></ul><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>故障锁存像跳闸。电压恢复正常只说明“当前读数不危险”，不等于“系统已经可以重新输出”。状态机让软件有一个明确流程：发现故障、停 PWM、等待复位请求、等待安全延时、再回到运行。</p><pre><code>RUN
PWM enable=1

FAULT_LATCHED
fault=OV, PWM=0

RESET_WAIT
等待复位延时

Vout &gt; OV

reset request

reset delay done, fault cleared
</code></pre><p>图 1：本节只讲故障锁存和复位，不展开完整 UPS 启动流程。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>下面的过压阈值（over-voltage threshold / OV）是保护边界，不是控制目标：</p><p>if state == RUN and Vout &gt; OV: fault = OV state = FAULT_LATCHED pwm_enable = 0</p><p>if state == FAULT_LATCHED and reset_request: state = RESET_WAIT</p><p>if state == RESET_WAIT and wait_time &gt;= reset_delay: fault = NONE state = RUN pwm_enable = 1</p><p>关键点：故障清除不是“电压低于阈值”一个条件，而是状态机条件。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行 Python 仿真：</p><p>cd E:\\gitee_CodeStorage\\学习\\电源 python simulations\\python\\boost_fault_state_machine.py</p><p>脚本会生成并自动打开图片；如果无法自动打开，会打印完整路径。图中包含输出电压、状态码、故障码、复位请求、PWM 使能和关键参数框。</p><pre><code>对比实验
python simulations\\python\\boost_fault_state_machine.py --reset-delay 0.002 --output simulations\\results\\boost_fault_reset_2ms.png
</code></pre><p>python simulations\\python\\boost_fault_state_machine.py --reset-delay 0.012 --output simulations\\results\\boost_fault_reset_12ms.png</p><p>比较两张图中 <code>RESET_WAIT</code> 状态持续时间和 PWM 重新使能时刻。</p><p>观察顺序：</p><ul><li><p>先看 <code>Vout</code> 是否短暂超过 OV 阈值。</p></li><li><p>再看状态是否进入 <code>FAULT_LATCHED</code>。</p></li><li><p>看复位请求出现后是否先进入 <code>RESET_WAIT</code>。</p></li><li><p>最后看 PWM 是否等复位延时结束后才恢复为 1。</p></li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>真实 C 工程里，相关逻辑通常分散在多个模块：</p><ul><li><p><code>protection.c</code>：检测故障，产生故障码。</p></li><li><p><code>state_machine.c</code>：决定运行、故障锁存、复位等待和重新启动。</p></li><li><p><code>pwm.c</code>：关断或释放 PWM 输出。</p></li><li><p><code>log.c</code> 或诊断模块：记录故障发生时的采样值和状态。</p></li></ul><p>读代码时要追踪三条线：故障码在哪里锁存、故障码在哪里清除、谁允许 PWM 重新打开。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>**误解：**故障采样恢复正常后就应该自动恢复。 **纠正：**严重故障通常需要锁存，并经过明确复位流程。</p></li><li><p>**误解：**状态机只是代码风格。 **纠正：**状态机决定系统何时允许输出，直接影响安全性和可调试性。</p></li><li><p>**误解：**复位按钮只是清故障码。 **纠正：**复位还要检查条件、等待延时，并确认输出处于安全状态。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li><p>能解释故障锁存（fault latch）和普通故障检测的区别。</p></li><li><p>能在仿真图中指出 <code>RUN</code>、<code>FAULT_LATCHED</code>、<code>RESET_WAIT</code> 三段。</p></li><li><p>能解释为什么 <code>Vout</code> 恢复正常后 PWM 仍然保持 0。</p></li><li><p>能说明复位请求（reset request）和复位延时（reset delay）不是同一件事。</p></li><li><p>能基于仿真图准备一个导师问题。</p></li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li><p>默认仿真中，过压脉冲开始于多少 ms，持续多少 ms？</p></li><li><p>复位请求出现后，为什么不立刻回到 <code>RUN</code>？</p></li><li><p>如果故障码由 <code>protection.c</code> 产生，应该由哪个模块清除？为什么？</p></li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li><p>我用 <code>boost_fault_state_machine.py</code> 看到过压脉冲结束后仍保持 <code>FAULT_LATCHED</code>。公司工程里哪些故障必须锁存，哪些允许自动恢复？</p></li><li><p>我把 <code>--reset-delay</code> 从 2 ms 改到 12 ms 后，PWM 重新使能时刻明显变化。真实工程里复位延时通常根据哪些硬件条件设置？</p></li><li><p>我看到图中 PWM 在故障期间保持 0。公司代码里软件 PWM 关断、硬件比较器关断和驱动芯片使能之间如何分工？</p></li></ul><p>**下一步：**把这节和第 6 节的 C 骨架连起来看：<code>Protection_Check()</code> 产生故障，<code>StateMachine_Step()</code> 决定何时允许恢复，<code>Pwm_ForceOff()</code> 保证输出关闭。</p><p>关联：<a href="./0006-boost-c-firmware-skeleton.html">上一节：Boost C 固件骨架</a>；源稿：<code>concepts/embedded/boost-fault-state-machine.md</code>。</p><pre><code>上一节：教程 0006：Boost C 固件骨架
下一节：教程 0008：Boost 慢速任务、遥测与故障日志
</code></pre>`,47)])])}const _=t(p,[["render",i]]);export{h as __pageData,_ as default};
